INSERT INTO quiz_questions (question, question_en, correct_answer, wrong_answers, explanation, explanation_en, category, difficulty, era) VALUES 
-- 1960s Political Crisis
('Πότε έγινε η παραίτηση του Καραμανλή;', 'When did Karamanlis resign?', '11 Ιουνίου 1963', '{"10 Ιουνίου 1963","12 Ιουνίου 1963","13 Ιουνίου 1963"}', 'Ο Κωνσταντίνος Καραμανλής παραιτήθηκε στις 11 Ιουνίου 1963.', 'Constantine Karamanlis resigned on June 11, 1963.', 'modern_history', 2, '1960-1970'),
('Ποιος έγινε πρωθυπουργός μετά την παραίτηση του Καραμανλή;', 'Who became PM after Karamanlis resignation?', 'Παναγιώτης Πιπινέλης', '{"Ιωάννης Παρασκευόπουλος","Στέφανος Στεφανόπουλος","Παναγιώτης Κανελλόπουλος"}', 'Ο Παναγιώτης Πιπινέλης έγινε πρωθυπουργός μετά τον Καραμανλή.', 'Panagiotis Pipinelis became PM after Karamanlis.', 'leaders', 2, '1960-1970'),
('Ποιος ήταν ο πρωθυπουργός κατά τις εκλογές του 1964;', 'Who was PM during the 1964 elections?', 'Ιωάννης Παρασκευόπουλος', '{"Παναγιώτης Κανελλόπουλος","Στέφανος Στεφανόπουλος","Ευάγγελος Αβέρωφ"}', 'Ο Ιωάννης Παρασκευόπουλος ήταν πρωθυπουργός κατά τις εκλογές Φεβρουαρίου 1964.', 'Ioannis Paraskevopoulos was PM during the February 1964 elections.', 'leaders', 3, '1960-1970'),
('Πότε έγινε η Άσκηση Περικλής;', 'When was Exercise Pericles?', 'Μάιος 1967', '{"Απρίλιος 1967","Ιούνιος 1967","Ιούλιος 1967"}', 'Η Άσκηση Περικλής ήταν στρατιωτικό σχέδιο που προετοίμαζε το πραξικόπημα.', 'Exercise Pericles was a military plan that prepared the coup.', 'modern_history', 3, '1967-1974'),

-- Junta Period (1967-1974)
('Ποιοι ήταν οι τρεις πρωταγωνιστές του πραξικοπήματος;', 'Who were the three protagonists of the coup?', 'Παπαδόπουλος, Παττακός, Μακαρέζος', '{"Παπαδόπουλος, Ιωαννίδης, Παττακός","Παττακός, Μακαρέζος, Ιωαννίδης","Παπαδόπουλος, Ιωαννίδης, Μακαρέζος"}', 'Οι συνταγματάρχες Παπαδόπουλος, Παττακός και Μακαρέζος ηγήθηκαν του πραξικοπήματος.', 'Colonels Papadopoulos, Pattakos and Makarezos led the coup.', 'modern_history', 2, '1967-1974'),
('Πότε κατήργησε την μοναρχία ο Παπαδόπουλος;', 'When did Papadopoulos abolish the monarchy?', '1 Ιουνίου 1973', '{"31 Μαΐου 1973","2 Ιουνίου 1973","3 Ιουνίου 1973"}', 'Ο Παπαδόπουλος κατήργησε τη μοναρχία την 1η Ιουνίου 1973.', 'Papadopoulos abolished the monarchy on June 1, 1973.', 'modern_history', 2, '1967-1974'),
('Ποιος ανέτρεψε τον Παπαδόπουλο;', 'Who overthrew Papadopoulos?', 'Δημήτριος Ιωαννίδης', '{"Στυλιανός Παττακός","Νικόλαος Μακαρέζος","Γρηγόριος Σπαντιδάκης"}', 'Ο Δημήτριος Ιωαννίδης ανέτρεψε τον Παπαδόπουλο τον Νοέμβριο του 1973.', 'Dimitrios Ioannidis overthrew Papadopoulos in November 1973.', 'modern_history', 1, '1967-1974'),
('Πότε έγινε το Πολυτεχνείο;', 'When did the Polytechnic uprising occur?', '14-17 Νοεμβρίου 1973', '{"13-16 Νοεμβρίου 1973","15-18 Νοεμβρίου 1973","12-15 Νοεμβρίου 1973"}', 'Η εξέγερση του Πολυτεχνείου έγινε 14-17 Νοεμβρίου 1973.', 'The Polytechnic uprising occurred November 14-17, 1973.', 'modern_history', 1, '1967-1974'),

-- Metapolitefsi Era (1974-1980)
('Πότε ήρθε ο Καραμανλής από το Παρίσι;', 'When did Karamanlis return from Paris?', '24 Ιουλίου 1974', '{"23 Ιουλίου 1974","25 Ιουλίου 1974","26 Ιουλίου 1974"}', 'Ο Καραμανλής επέστρεψε από το Παρίσι στις 24 Ιουλίου 1974.', 'Karamanlis returned from Paris on July 24, 1974.', 'modern_history', 1, '1974-1980'),
('Ποιος ήταν ο πρώτος υπουργός Εσωτερικών της Μεταπολίτευσης;', 'Who was the first Interior Minister of Metapolitefsi?', 'Γεώργιος Μαύρος', '{"Ευάγγελος Αβέρωφ","Παναγιώτης Κανελλόπουλος","Κωνσταντίνος Μητσοτάκης"}', 'Ο Γεώργιος Μαύρος ήταν ο πρώτος υπουργός Εσωτερικών του Καραμανλή.', 'Georgios Mavros was Karamanlis first Interior Minister.', 'leaders', 3, '1974-1980'),
('Πότε έγινε το δημοψήφισμα για το πολίτευμα;', 'When was the referendum on the political system?', '8 Δεκεμβρίου 1974', '{"7 Δεκεμβρίου 1974","9 Δεκεμβρίου 1974","10 Δεκεμβρίου 1974"}', 'Το δημοψήφισμα για δημοκρατία ή μοναρχία έγινε στις 8 Δεκεμβρίου 1974.', 'The referendum on republic or monarchy was on December 8, 1974.', 'constitutional', 1, '1974-1980'),
('Ποιο ποσοστό υπέρ της δημοκρατίας πήρε το δημοψήφισμα;', 'What percentage for the republic did the referendum get?', '69,18%', '{"65,5%","72,3%","58,2%"}', 'Η δημοκρατία έλαβε 69,18% στο δημοψήφισμα του 1974.', 'The republic received 69.18% in the 1974 referendum.', 'constitutional', 2, '1974-1980'),

-- PASOK Era (1981-1989)
('Πότε έγινε η πρώτη εκλογική νίκη του ΠΑΣΟΚ;', 'When was PASOK first electoral victory?', '18 Οκτωβρίου 1981', '{"17 Οκτωβρίου 1981","19 Οκτωβρίου 1981","20 Οκτωβρίου 1981"}', 'Το ΠΑΣΟΚ νίκησε για πρώτη φορά στις εκλογές της 18ης Οκτωβρίου 1981.', 'PASOK won for the first time in the October 18, 1981 elections.', 'modern_history', 1, '1980-1990'),
('Ποιος ήταν ο πρώτος υπουργός Εξωτερικών του ΠΑΣΟΚ;', 'Who was PASOK first Foreign Minister?', 'Ιωάννης Χαραλαμπόπουλος', '{"Κάρολος Παπούλιας","Αντώνης Σαμαράς","Θεόδωρος Πάγκαλος"}', 'Ο Ιωάννης Χαραλαμπόπουλος ήταν ο πρώτος υπουργός Εξωτερικών του ΠΑΣΟΚ.', 'Ioannis Charalambopoulos was PASOK first Foreign Minister.', 'leaders', 3, '1980-1990'),
('Πότε έγινε η διαδικασία για τα σκάνδαλα της κυβέρνησης Παπανδρέου;', 'When was the process for the Papandreou government scandals?', '1989', '{"1988","1990","1991"}', 'Η δικαστική διαδικασία για τα σκάνδαλα της κυβέρνησης Παπανδρέου έγινε το 1989.', 'The judicial process for the Papandreou government scandals was in 1989.', 'modern_history', 2, '1980-1990'),
('Ποιος ήταν ο υπουργός Εθνικής Άμυνας που παραιτήθηκε το 1988;', 'Who was the Defense Minister who resigned in 1988?', 'Ευάγγελος Κουλουμπής', '{"Γεράσιμος Αρσένης","Ιωάννης Βαρβιτσιώτης","Άκης Τσοχατζόπουλος"}', 'Ο Ευάγγελος Κουλουμπής παραιτήθηκε από υπουργός Άμυνας το 1988.', 'Evangelos Kouloumbis resigned as Defense Minister in 1988.', 'leaders', 3, '1980-1990'),

-- Political Crisis 1989-1990
('Ποιος ήταν ο πρωθυπουργός του συνασπισμού ΝΔ-ΣΥΝΠΟ;', 'Who was the PM of the ND-SYN coalition?', 'Τζαννής Τζανετάκης', '{"Ξενοφών Ζολώτας","Γρηγόρης Βαρφής","Ιωάννης Κασιδιάρης"}', 'Ο Τζαννής Τζανετάκης ήταν πρωθυπουργός του συνασπισμού ΝΔ-ΣΥΝ το 1989.', 'Tzannis Tzanetakis was PM of the ND-SYN coalition in 1989.', 'leaders', 2, '1989-1990'),
('Πότε έγινε η πρώτη κυβέρνηση οικουμενικής συνεργασίας;', 'When was the first government of national cooperation?', 'Νοέμβριος 1989', '{"Οκτώβριος 1989","Δεκέμβριος 1989","Ιανουάριος 1990"}', 'Η κυβέρνηση Ζολώτα σχηματίστηκε τον Νοέμβριο του 1989.', 'The Zolotas government was formed in November 1989.', 'modern_history', 2, '1989-1990'),
('Ποιος ήταν ο τελευταίος Πρόεδρος που εξελέγη από μειοψηφία;', 'Who was the last President elected by a minority?', 'Κωνσταντίνος Στεφανόπουλος', '{"Κάρολος Παπούλιας","Προκόπης Παυλόπουλος","Χρήστος Σαρτζετάκης"}', 'Ο Κωνσταντίνος Στεφανόπουλος εξελέγη με λιγότερο από 200 ψήφους.', 'Konstantinos Stephanopoulos was elected with less than 200 votes.', 'constitutional', 3, '1990-2000'),

